<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Sorting Algorithm Visualizer</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            background-color: #121212;
            color: #e0e0e0;
            display: flex;
            flex-direction: column;
            align-items: center;
            min-height: 100vh;
            padding: 20px;
        }

        h1 {
            margin-bottom: 20px;
            color: #bb86fc;
        }

        .controls {
            display: flex;
            gap: 15px;
            margin-bottom: 30px;
        }

        button {
            padding: 10px 20px;
            font-size: 16px;
            border: none;
            border-radius: 5px;
            cursor: pointer;
            transition: all 0.2s ease;
            background-color: #3700b3;
            color: white;
        }

        button:hover {
            background-color: #6200ee;
            transform: translateY(-2px);
        }

        button:active {
            transform: translateY(0);
        }

        .visualizer-container {
            width: 100%;
            max-width: 800px;
            height: 400px;
            background-color: #1e1e1e;
            border-radius: 10px;
            padding: 20px;
            display: flex;
            align-items: flex-end;
            justify-content: space-between;
        }

        .bar {
            width: 30px;
            margin-right: 5px;
            background-color: #03dac6;
            border-radius: 5px 5px 0 0;
            transition: height 0.2s ease;
            position: relative;
        }

        .bar:last-child {
            margin-right: 0;
        }

        .bar:hover::after {
            content: attr(data-value);
            position: absolute;
            top: -25px;
            left: 50%;
            transform: translateX(-50%);
            background-color: #333;
            color: white;
            padding: 2px 6px;
            border-radius: 4px;
            font-size: 12px;
        }

        .status {
            margin-top: 20px;
            font-size: 18px;
            color: #bb86fc;
        }
    </style>
</head>
<body>
    <h1>Sorting Algorithm Visualizer</h1>

    <div class="controls">
        <button id="sort">Sort</button>
        <button id="shuffle">Shuffle</button>
        <button id="reset">Reset</button>
    </div>

    <div class="visualizer-container" id="bars"></div>
    <div class="status" id="status">Ready to sort</div>

    <script>
        // Visualizer state
        let array = [];
        let originalArray = [];
        let isSorting = false;
        let sortGenerator = null;

        // DOM elements
        const barsContainer = document.getElementById('bars');
        const statusElement = document.getElementById('status');
        const sortButton = document.getElementById('sort');
        const shuffleButton = document.getElementById('shuffle');
        const resetButton = document.getElementById('reset');

        // Initialize with a default array
        function init() {
            setArray([5, 3, 8, 1, 9, 2, 7, 4, 6]);
        }

        // Generate random array
        function generateRandomArray(size = 10) {
            const arr = [];
            for (let i = 1; i <= size; i++) {
                arr.push(Math.floor(Math.random() * 90) + 10);
            }
            return arr;
        }

        // Set the array and redraw
        function setArray(arr) {
            array = [...arr];
            originalArray = [...arr];
            renderBars();
            statusElement.textContent = 'Ready to sort';
        }

        // Render bars based on current array values
        function renderBars() {
            barsContainer.innerHTML = '';

            if (array.length === 0) return;

            const maxValue = Math.max(...array);

            array.forEach(value => {
                const bar = document.createElement('div');
                bar.className = 'bar';

                // Calculate height as percentage of max value
                const heightPercentage = (value / maxValue) * 100;
                bar.style.height = `${heightPercentage}%`;
                bar.dataset.value = value;

                barsContainer.appendChild(bar);
            });
        }

        // Check if array is sorted
        function sorted() {
            for (let i = 1; i < array.length; i++) {
                if (array[i] < array[i - 1]) {
                    return false;
                }
            }
            return true;
        }

        // Generator-based merge sort implementation
        function* mergeSortGenerator(arr, start = 0, end = arr.length) {
            if (end - start <= 1) {
                yield { type: 'compare', indices: [start, start] };
                return;
            }

            const mid = Math.floor((start + end) / 2);

            // Sort left half
            yield* mergeSortGenerator(arr, start, mid);

            // Sort right half
            yield* mergeSortGenerator(arr, mid, end);

            // Merge the two sorted halves
            let left = start;
            let right = mid;
            const temp = [];

            while (left < mid && right < end) {
                yield { type: 'compare', indices: [left, right] };

                if (arr[left] <= arr[right]) {
                    temp.push(arr[left]);
                    left++;
                } else {
                    temp.push(arr[right]);
                    right++;
                }
            }

            while (left < mid) {
                yield { type: 'compare', indices: [left, left] };
                temp.push(arr[left]);
                left++;
            }

            while (right < end) {
                yield { type: 'compare', indices: [right, right] };
                temp.push(arr[right]);
                right++;
            }

            // Update original array with merged values
            for (let i = 0; i < temp.length; i++) {
                arr[start + i] = temp[i];
                yield { type: 'update', index: start + i, value: temp[i] };
            }
        }

        // Generator-based quicksort implementation
        function* quickSortGenerator(arr, low = 0, high = null) {
            if (high === null) high = arr.length - 1;

            if (low < high) {
                const pi = yield* partitionGenerator(arr, low, high);
                yield* quickSortGenerator(arr, low, pi - 1);
                yield* quickSortGenerator(arr, pi + 1, high);
            }
        }

        function* partitionGenerator(arr, low, high) {
            const pivot = arr[high];
            let i = low - 1;

            for (let j = low; j <= high - 1; j++) {
                yield { type: 'compare', indices: [j, high] };

                if (arr[j] < pivot) {
                    i++;
                    // Swap arr[i] and arr[j]
                    yield { type: 'swap', indices: [i, j] };
                    [arr[i], arr[j]] = [arr[j], arr[i]];
                }
            }

            // Swap arr[i+1] and arr[high] (pivot)
            yield { type: 'swap', indices: [i + 1, high] };
            [arr[i + 1], arr[high]] = [arr[high], arr[i + 1]];

            return i + 1;
        }

        // Generator-based bubble sort implementation
        function* bubbleSortGenerator(arr) {
            const n = arr.length;

            for (let i = 0; i < n - 1; i++) {
                let swapped = false;

                for (let j = 0; j < n - i - 1; j++) {
                    yield { type: 'compare', indices: [j, j + 1] };

                    if (arr[j] > arr[j + 1]) {
                        // Swap elements
                        yield { type: 'swap', indices: [j, j + 1] };
                        [arr[j], arr[j + 1]] = [arr[j + 1], arr[j]];
                        swapped = true;
                    }
                }

                if (!swapped) break;
            }
        }

        // Generator-based insertion sort implementation
        function* insertionSortGenerator(arr) {
            for (let i = 1; i < arr.length; i++) {
                let key = arr[i];
                let j = i - 1;

                while (j >= 0 && arr[j] > key) {
                    yield { type: 'compare', indices: [j, i] };

                    arr[j + 1] = arr[j];
                    yield { type: 'update', index: j + 1, value: arr[j] };
                    j--;
                }

                arr[j + 1] = key;
                yield { type: 'update', index: j + 1, value: key };
            }
        }

        // Start sorting with the selected algorithm
        function startSort() {
            if (sorted()) return;

            isSorting = true;
            statusElement.textContent = 'Sorting...';

            // Use insertion sort as it's simple and works well for visualization
            sortGenerator = insertionSortGenerator(array);
        }

        // Perform one step of sorting
        function sortStep() {
            if (!isSorting) return false;

            const result = sortGenerator.next();

            if (result.done) {
                isSorting = false;
                statusElement.textContent = 'Sorting complete!';
                renderBars(); // Final render to ensure all updates are shown
                return true;
            }

            // Update visualization based on the step type
            const step = result.value;
            if (step.type === 'swap' || step.type === 'update') {
                renderBars();

                // Highlight updated bars
                const bars = document.querySelectorAll('.bar');
                if (step.index !== undefined) {
                    bars[step.index].style.backgroundColor = '#ff4081';
                    setTimeout(() => {
                        bars[step.index].style.backgroundColor = '';
                    }, 200);
                } else if (step.indices) {
                    step.indices.forEach(idx => {
                        if (idx < bars.length) {
                            bars[idx].style.backgroundColor = '#ff4081';
                        }
                    });
                    setTimeout(() => {
                        const bars = document.querySelectorAll('.bar');
                        step.indices.forEach(idx => {
                            if (idx < bars.length) {
                                bars[idx].style.backgroundColor = '';
                            }
                        });
                    }, 200);
                }
            } else if (step.type === 'compare') {
                // Highlight compared bars briefly
                const bars = document.querySelectorAll('.bar');
                step.indices.forEach(idx => {
                    if (idx < bars.length) {
                        bars[idx].style.backgroundColor = '#03dac6';
                    }
                });
                setTimeout(() => {
                    const bars = document.querySelectorAll('.bar');
                    step.indices.forEach(idx => {
                        if (idx < bars.length) {
                            bars[idx].style.backgroundColor = '';
                        }
                    });
                }, 150);
            }

            return false;
        }

        // Shuffle the array
        function shuffleArray() {
            const newArray = [...array];
            for (let i = newArray.length - 1; i > 0; i--) {
                const j = Math.floor(Math.random() * (i + 1));
                [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
            }
            setArray(newArray);
        }

        // Reset to original array
        function resetArray() {
            setArray(originalArray);
        }

        // Event listeners
        sortButton.addEventListener('click', () => {
            if (!isSorting) {
                startSort();
                // Run sorting steps with animation
                const interval = setInterval(() => {
                    if (sortStep()) {
                        clearInterval(interval);
                    }
                }, 100); // Adjust speed as needed
            }
        });

        shuffleButton.addEventListener('click', shuffleArray);
        resetButton.addEventListener('click', resetArray);

        // Expose API on window
        window.viz = {
            array: () => [...array],
            setArray: (a) => setArray(a),
            sortStep: () => sortStep(),
            sorted: () => sorted()
        };

        // Initialize the visualizer
        init();
    </script>
</body>
</html>
